INSERT OR IGNORE INTO `item_types` (`id`, `name`, `description`, `color`, `icon`, `guidance`, `is_system`, `sort_order`, `created_at`, `updated_at`) VALUES ('5dbd0621-1270-4585-80e2-565b76e631c7', 'Interview', 'Conversation with a guest', '#8B5CF6', '🎙️', '{"pattern":"Ep. [N]: [Guest Name] on [Topic]","example":"Ep. 12: Sarah Chen on building developer tools at scale","whenToUse":"Use for episodes featuring a guest conversation or Q&A","contentHints":"Include guest bio, key topics with timestamps, notable quotes, and links mentioned. Use ## headings for major topic shifts."}', 1, 0, '2026-03-27T01:22:52.957Z', '2026-03-27T01:22:52.957Z');
