-- podcast-specific settings
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_title', 'My Podcast', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_description', 'Episode show notes and archive', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Use the format: Ep. [Number]: [Title or Guest — Topic]. Include the episode number for chronological ordering."},"content":{"tips":"Write structured show notes. Lead with a one-paragraph summary, then timestamps, then links and resources mentioned."},"formatting":["Timestamps: use [00:00] format at the start of lines for topic markers","Headings: separate Guest Bio, Topics, Links, and Timestamps sections","Bullet lists: links mentioned, resources, guest social handles","Numbered lists: key takeaways or episode highlights","Blockquotes: notable quotes from guests","Bold: guest names and topic labels within show notes"],"avoid":["Full transcripts in show notes (link to them instead)","Missing episode numbers (chronological ordering matters)","Show notes without timestamps (listeners need navigation)","Vague summaries like \"Great conversation about tech\""]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":10,"max":200},"content":{"min":50,"max":15000},"sourceAi":{"min":1,"max":100}}', datetime('now'));

-- Site actions (podcast)
INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('96b3fbe5-4fb7-4d6e-8ffe-67288cb293ab', 'Guest Application', 'guest-application', 'Apply to be a guest on the show', '[{"name":"name","type":"text","label":"Name","required":true,"placeholder":"Your name","maxLength":100},{"name":"email","type":"email","label":"Email","required":true,"placeholder":"you@example.com"},{"name":"website","type":"url","label":"Website or Profile","required":false,"placeholder":"https://yoursite.com","maxLength":500},{"name":"pitch","type":"textarea","label":"Why would you be a great guest?","required":true,"placeholder":"Tell us about your expertise and what topics you could discuss...","maxLength":2000}]', '{"success_message":"Thanks for applying! We''ll review your application and reach out if there''s a fit.","require_honeypot":true}', 'active', '2026-03-27T01:22:52.957Z', '2026-03-27T01:22:52.957Z');
INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('ce4fc647-94bb-42d4-8c8c-7e5d92698c9c', 'Topic Suggestion', 'topic-suggestion', 'Suggest a topic for a future episode', '[{"name":"name","type":"text","label":"Name","required":true,"placeholder":"Your name","maxLength":100},{"name":"email","type":"email","label":"Email","required":true,"placeholder":"you@example.com"},{"name":"topic","type":"textarea","label":"Topic Suggestion","required":true,"placeholder":"What topic would you like us to cover?","maxLength":2000}]', '{"success_message":"Great suggestion! We''ll add it to our episode planning list.","require_honeypot":true}', 'active', '2026-03-27T01:22:52.957Z', '2026-03-27T01:22:52.957Z');
